/*
     SQL ID : FileMgrDAO.updateAuthGrpSizeLimit
     설  명 : 권한 그룹의 용량 변경
 */
UPDATE TB_LMS_AUTHRT_GRP
   SET ATFL_MAXSZ = #{fileSize, javaType=int, jdbcType=INTEGER}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
 WHERE USER_AUTHRT_ID = #{selectedAthGrpCd}
   AND ORG_ID = #{userOrgId}

/*
     SQL ID : FileMgrDAO.updateUserSizeLimit
     설  명 : 사용자의 용량 변경
 */
UPDATE TB_LMS_USER_AUTHRT
   SET ATFL_MAXSZ = #{fileSize, javaType=int, jdbcType=INTEGER}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
 WHERE MENU_TYCD = 'HOME'
   AND USER_AUTHRT_ID = #{selectedAthGrpCd}
   AND USER_ID = #{selectedUserId}

