/*
     SQL ID : FileMgrDAO.listLmsTerm
     설  명 : 학기 목록를 조회한다.
 */
SELECT CRS_SMSTR_ID
     , SMSTRNM
  FROM CRS_SMSTR
 WHERE ORG_ID = #{userOrgId}
   AND SMSTR_STSCD = 'SERVICE'
   AND SMSTR_TYCD = #{searchType}

mapper.sql:
SELECT ROW_NUMBER() OVER (ORDER BY B.SBJCTNM DESC) AS ROW_NUM , A.CRS_ID , B.SBJCT_ID , B.SBJCTNM , B.DVCLAS_NO , B.SBJCT_OP_TYCD AS LEARNING_TYPE , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'LEARNING_TYPE' AND CD = B.SBJCT_OP_TYCD) AS LEARNING_TYPE_NM , B.CMCRS_GBNCD AS COURSE_TYPE , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'CMCRS_GBNCD' AND CD = B.CMCRS_GBNCD) AS COURSE_TYPE_NM , IFNULL(E.BBS_ATFL_MAXSZ, F.BBS_ATFL_MAXSZ) AS BBS_FILE_SIZE , IFNULL(E.DSCS_ATFL_MAXSZ, F.DSCS_ATFL_MAXSZ) AS FORUM_FILE_SIZE , IFNULL(E.ASMT_ATFL_MAXSZ, F.ASMT_ATFL_MAXSZ) AS ASMT_FILE_SIZE , IFNULL(E.EXAM_ATFL_MAXSZ, F.EXAM_ATFL_MAXSZ) AS EXAM_FILE_SIZE , IFNULL(E.TEAM_ACTV_ATFL_MAXSZ, F.TEAM_ACTV_ATFL_MAXSZ) AS TEAM_FILE_SIZE , IFNULL(E.LCTR_ATFL_MAXSZ, F.LCTR_ATFL_MAXSZ) AS LECTURE_FILE_SIZE , C.USER_ID AS PROFESSOR_NO , D.USERNM AS PROFESSOR_NM FROM TB_LMS_CRS A JOIN TB_LMS_SBJCT B ON A.CRS_ID = B.CRS_ID LEFT JOIN SBJCT_PROF C ON B.SBJCT_ID = C.SBJCT_ID AND C.RPRSYN = 'Y' LEFT JOIN TB_LMS_USR D ON C.USER_ID = D.USER_ID LEFT JOIN TB_LMS_SBJCT_ATFL_MAXSZ E ON B.SBJCT_ID = E.SBJCT_ID CROSS JOIN ( SELECT MAX(IF(MAXSZ_DTL_TYCD = 'LECT_BBS', MAXSZ, 0)) AS BBS_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'FORUM', MAXSZ, 0)) AS DSCS_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'ASMNT', MAXSZ, 0)) AS ASMT_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'EXAM_ID', MAXSZ, 0)) AS EXAM_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'PROJECT', MAXSZ, 0)) AS TEAM_ACTV_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'LECTURE', MAXSZ, 0)) AS LCTR_ATFL_MAXSZ FROM ATFL_MAXSZ WHERE MAXSZ_TYCD = 'CLASS' ) F WHERE A.ORG_ID = #{userOrgId} AND A.USEYN = 'Y' AND B.USEYN = 'Y' AND B.DELYN = 'N'
AND EXISTS ( SELECT 1 FROM TB_LMS_TERM_CRE_CRS_RLTN AA JOIN CRS_SMSTR BB ON AA.CRS_SMSTR_ID = BB.CRS_SMSTR_ID WHERE AA.SBJCT_ID = B.SBJCT_ID AND BB.SMSTR_TYCD = #{searchType} AND BB.SMSTR_STSCD = 'SERVICE'
AND AA.CRS_SMSTR_ID = #{searchCreTerm}
)
AND ( B.SBJCTNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci OR D.USERNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci )
AND A.SBJCT_TYCD = #{crsTypeCd}
AND B.SBJCT_ID = #{creYear}

mapper.select:
/* SQL ID : FileMgrDAO.selectCrsSizeLimitCount 설 명 : 과목별 용량관리 리스트의 카운트 */ SELECT COUNT(1) FROM TB_LMS_CRS A JOIN TB_LMS_SBJCT B ON A.CRS_ID = B.CRS_ID LEFT JOIN SBJCT_PROF C ON B.SBJCT_ID = C.SBJCT_ID AND C.RPRSYN = 'Y' LEFT JOIN TB_LMS_USR D ON C.USER_ID = D.USER_ID LEFT JOIN TB_LMS_SBJCT_ATFL_MAXSZ E ON B.SBJCT_ID = E.SBJCT_ID CROSS JOIN ( SELECT MAX(IF(MAXSZ_DTL_TYCD = 'LECT_BBS', MAXSZ, 0)) AS BBS_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'FORUM', MAXSZ, 0)) AS DSCS_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'ASMNT', MAXSZ, 0)) AS ASMT_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'EXAM_ID', MAXSZ, 0)) AS EXAM_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'PROJECT', MAXSZ, 0)) AS TEAM_ACTV_ATFL_MAXSZ , MAX(IF(MAXSZ_DTL_TYCD = 'LECTURE', MAXSZ, 0)) AS LCTR_ATFL_MAXSZ FROM ATFL_MAXSZ WHERE MAXSZ_TYCD = 'CLASS' ) F WHERE A.ORG_ID = #{userOrgId} AND A.USEYN = 'Y' AND B.USEYN = 'Y' AND B.DELYN = 'N'
AND EXISTS ( SELECT 1 FROM TB_LMS_TERM_CRE_CRS_RLTN AA JOIN CRS_SMSTR BB ON AA.CRS_SMSTR_ID = BB.CRS_SMSTR_ID WHERE AA.SBJCT_ID = B.SBJCT_ID AND BB.SMSTR_TYCD = #{searchType} AND BB.SMSTR_STSCD = 'SERVICE'
AND AA.CRS_SMSTR_ID = #{searchCreTerm}
)
AND ( B.SBJCTNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci OR D.USERNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci )
AND A.SBJCT_TYCD = #{crsTypeCd}
AND B.SBJCT_ID = #{creYear}

