/*
     SQL ID : FileMgrDAO.updateCrsSizeLimit
     설  명 : 과목의 용량 변경
 */
INSERT INTO TB_LMS_SBJCT_ATFL_MAXSZ (
       SBJCT_ID
     , BBS_ATFL_MAXSZ
     , ASMT_ATFL_MAXSZ
     , EXAM_ATFL_MAXSZ
     , DSCS_ATFL_MAXSZ
     , TEAM_ACTV_ATFL_MAXSZ
     , LCTR_ATFL_MAXSZ
     , RGTR_ID
     , FRST_INQ_DTTM
     , MDFR_ID
     , MOD_DTTM
) VALUES (
       #{selectedCrsCreCd}
     , IF(#{limitTypeDetlCd} = 'LECT_BBS', #{limitFileSize, javaType=int, jdbcType=INTEGER}, NULL)
     , IF(#{limitTypeDetlCd} = 'ASMNT', #{limitFileSize, javaType=int, jdbcType=INTEGER}, NULL)
     , IF(#{limitTypeDetlCd} = 'EXAM_ID', #{limitFileSize, javaType=int, jdbcType=INTEGER}, NULL)
     , IF(#{limitTypeDetlCd} = 'FORUM', #{limitFileSize, javaType=int, jdbcType=INTEGER}, NULL)
     , IF(#{limitTypeDetlCd} = 'PROJECT', #{limitFileSize, javaType=int, jdbcType=INTEGER}, NULL)
     , IF(#{limitTypeDetlCd} = 'LECTURE', #{limitFileSize, javaType=int, jdbcType=INTEGER}, NULL)
     , #{mdfrId}
     , FN_DTTM()
     , #{mdfrId}
     , FN_DTTM()
)
ON DUPLICATE KEY
UPDATE
       MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()

     , BBS_ATFL_MAXSZ = #{limitFileSize, javaType=int, jdbcType=INTEGER} 


     , DSCS_ATFL_MAXSZ = #{limitFileSize, javaType=int, jdbcType=INTEGER} 


     , ASMT_ATFL_MAXSZ = #{limitFileSize, javaType=int, jdbcType=INTEGER} 


     , EXAM_ATFL_MAXSZ = #{limitFileSize, javaType=int, jdbcType=INTEGER} 


     , TEAM_ACTV_ATFL_MAXSZ = #{limitFileSize, javaType=int, jdbcType=INTEGER} 


     , LCTR_ATFL_MAXSZ = #{limitFileSize, javaType=int, jdbcType=INTEGER}

/*
     SQL ID : FileMgrDAO.updateDefaultCrsSizeLimit
     설  명 : 과목별 초기 용량 설정 변경
 */
UPDATE ATFL_MAXSZ
   SET MAXSZ = #{limitFileSize}
     , MDFR_ID = #{mdfrId}
     , MOD_DTTM = FN_DTTM()
 WHERE ATFL_MAXSZ_ID = #{fileSizeLimitId}
